-- ============================================================\n-- PRODUCT & SERVICE PLATFORM — Migration 12: RBAC & Configurable Pricing Engine\n-- ============================================================\n\n-- Departments / Roles\nCREATE TABLE IF NOT EXISTS public.admin_roles (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  role_name TEXT NOT NULL UNIQUE CHECK (role_name IN ('SuperAdmin','FinanceAdmin','OpsAdmin','SupportAdmin')),\n  permissions TEXT[] DEFAULT '{}'::text[],\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Populate default roles with specific permissions\nINSERT INTO public.admin_roles (role_name, permissions)\nVALUES \n  ('SuperAdmin', ARRAY['manage_users', 'manage_settings', 'manage_pricing', 'view_reports', 'view_logs']),\n  ('FinanceAdmin', ARRAY['manage_pricing', 'view_reports']),\n  ('OpsAdmin', ARRAY['view_reports', 'manage_settings']),\n  ('SupportAdmin', ARRAY['view_logs'])\nON CONFLICT (role_name) DO UPDATE\nSET permissions = EXCLUDED.permissions;\n\n-- User roles assignment table\nCREATE TABLE IF NOT EXISTS public.admin_user_roles (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE UNIQUE NOT NULL,\n  role_id BIGINT REFERENCES public.admin_roles(id) ON DELETE RESTRICT NOT NULL,\n  assigned_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Configurable pricing rules\nCREATE TABLE IF NOT EXISTS public.pricing_rules (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  rule_name TEXT NOT NULL UNIQUE,\n  margin_percentage NUMERIC(5,2) NOT NULL DEFAULT 10.00,\n  seasonal_coefficient NUMERIC(3,2) NOT NULL DEFAULT 1.00,\n  segment_coefficient NUMERIC(3,2) NOT NULL DEFAULT 1.00,\n  is_active BOOLEAN DEFAULT TRUE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Default rule\nINSERT INTO public.pricing_rules (rule_name, margin_percentage, seasonal_coefficient, segment_coefficient)\nVALUES ('Standard Rule', 15.00, 1.00, 1.00)\nON CONFLICT (rule_name) DO NOTHING;\n\n-- Configurable pricing formulas\nCREATE TABLE IF NOT EXISTS public.pricing_formulas (\n  id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,\n  formula_name TEXT NOT NULL UNIQUE,\n  formula_expression TEXT NOT NULL, -- e.g. '(cogs * seasonal) + margin'\n  description TEXT,\n  is_selected BOOLEAN DEFAULT FALSE,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT NOW()\n);\n\n-- Default formula\nINSERT INTO public.pricing_formulas (formula_name, formula_expression, description, is_selected)\nVALUES ('Standard Formula', '(cogs * seasonal) + margin', 'Standard weighted price formula', TRUE)\nON CONFLICT (formula_name) DO NOTHING;\n\n-- Enable RLS\nALTER TABLE public.admin_roles ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.admin_user_roles ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.pricing_rules ENABLE ROW LEVEL SECURITY;\nALTER TABLE public.pricing_formulas ENABLE ROW LEVEL SECURITY;\n\n-- Policies\nCREATE POLICY \"Roles visible to authenticated\"\n  ON public.admin_roles FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"User roles visible to authenticated\"\n  ON public.admin_user_roles FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"User roles editable by superadmin\"\n  ON public.admin_user_roles FOR ALL TO authenticated USING (TRUE);\n\nCREATE POLICY \"Pricing rules visible to authenticated\"\n  ON public.pricing_rules FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"Pricing rules editable by finance and superadmin\"\n  ON public.pricing_rules FOR ALL TO authenticated USING (TRUE);\n\nCREATE POLICY \"Pricing formulas visible to authenticated\"\n  ON public.pricing_formulas FOR SELECT TO authenticated USING (TRUE);\n\nCREATE POLICY \"Pricing formulas editable by finance and superadmin\"\n  ON public.pricing_formulas FOR ALL TO authenticated USING (TRUE);\n
